mapper.select:
WITH RECURSIVE category_tree AS ( SELECT id FROM categories WHERE id = #{request.categoryId}
UNION ALL
SELECT c.id FROM categories c JOIN category_tree ct ON c.parent_id = ct.id )
SELECT p.id AS productId, p.name, p.price, pi.photo_path AS thumbnailPath FROM products p
LEFT JOIN product_images pi ON pi.product_id = p.id AND pi.sort_order = 1
p.status != 'DELETED'
AND p.name LIKE CONCAT('%', #{request.keyword}, '%')
AND p.category_id IN ( SELECT id FROM category_tree )
AND p.seller_id = #{request.sellerId}
ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE products p
SET stock = stock - #{quantity}
where id = #{id}
and stock >= #{quantity}

UPDATE products
SET stock = stock + #{quantity}
WHERE id = #{id}
